mapper.select:
SELECT MAC as mac, TIME, ROUND(avgMerge(RX_FLOW_AVG),2) as rxFlow, ROUND(avgMerge(TX_FLOW_AVG),2) as txFlow
FROM AGG_VSWITCH_PORT_FLOW_30M  WHERE TIME BETWEEN ${startTime} AND ${endTime} AND DOMAIN_ID=${domainId}

    AND MAC like #{mac}

GROUP BY MAC, TIME
ORDER BY TIME ASC

SELECT DOMAIN_ID as domainId, TD.title as title,


        ROUND(sum(RX_FLOW_AVG * if((${endTime} - toUnixTimestamp(TIME)) > 1800, 1800, ${endTime} - toUnixTimestamp(TIME))),2) +
        ROUND(sum(TX_FLOW_AVG * if((${endTime} - toUnixTimestamp(TIME)) > 1800, 1800, ${endTime} - toUnixTimestamp(TIME))),2) as allFlow


        ROUND(sum(RX_FLOW_AVG * if((${endTime} - toUnixTimestamp(TIME)) > 1800, 1800, ${endTime} - toUnixTimestamp(TIME))),2) allFlow


        ROUND(sum(TX_FLOW_AVG * if((${endTime} - toUnixTimestamp(TIME)) > 1800, 1800, ${endTime} - toUnixTimestamp(TIME))),2) allFlow


FROM (SELECT DOMAIN_ID, TIME, MAC,


        avgMerge(RX_FLOW_AVG) AS RX_FLOW_AVG,  avgMerge(TX_FLOW_AVG) AS TX_FLOW_AVG


        avgMerge(RX_FLOW_AVG) AS RX_FLOW_AVG


        avgMerge(TX_FLOW_AVG) AS TX_FLOW_AVG


FROM AGG_VSWITCH_PORT_FLOW_30M
WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND HOST_POOL_ID =${hostPoolId}


    AND CLUSTER_ID =${clusterId}


    AND HOST_ID =${hostId}


    AND OP_GROUP_CODE LIKE #{operatorGroupCode}

GROUP BY HOST_POOL_ID, CLUSTER_ID, HOST_ID, DOMAIN_ID, MAC, TIME) FLOW,
${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_DOMAIN} TD
WHERE TD.id = FLOW.DOMAIN_ID
GROUP BY FLOW.DOMAIN_ID,TD.title  ORDER BY allFlow DESC

    LIMIT ${limit}

SELECT MAC as mac, DOMAIN_ID as domainId, ROUND(avgMerge(RX_FLOW_AVG),2) as avgRxFlow , maxMerge(RX_FLOW_MAX) as maxRxFlow, minMerge(RX_FLOW_MIN) as minRxFlow,
ROUND(avgMerge(TX_FLOW_AVG),2) as avgTxFlow , maxMerge(TX_FLOW_MAX) as maxTxFlow, minMerge(TX_FLOW_MIN) as minTxFlow
FROM AGG_VSWITCH_PORT_FLOW_30M detail  WHERE TIME BETWEEN ${startTime} AND ${endTime}

    AND DOMAIN_ID = ${domainId}


    AND DOMAIN_ID in (${vmIds})

GROUP BY DOMAIN_ID, MAC;
